import{_ as a,o as s,c as t,ag as e}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"01 — Luồng nghiệp vụ cốt lõi","description":"","frontmatter":{},"headers":[],"relativePath":"01-nghiep-vu/01-luong-nghiep-vu-cot-loi.md","filePath":"01-nghiep-vu/01-luong-nghiep-vu-cot-loi.md"}'),o={name:"01-nghiep-vu/01-luong-nghiep-vu-cot-loi.md"};function i(p,n,l,c,d,r){return s(),t("div",null,[...n[0]||(n[0]=[e(`<h1 id="_01-—-luong-nghiep-vu-cot-loi" tabindex="-1">01 — Luồng nghiệp vụ cốt lõi <a class="header-anchor" href="#_01-—-luong-nghiep-vu-cot-loi" aria-label="Permalink to &quot;01 — Luồng nghiệp vụ cốt lõi&quot;">​</a></h1><blockquote><p><strong>Vai trò đọc</strong>: BA, dev — hiểu hệ thống vận hành như thế nào ở mức business flow trước khi đụng code/schema. <strong>File này có</strong>: 2 flow chính (Series Tour + Private Tour) + status transitions + edge cases.</p></blockquote><hr><h2 id="tom-tat-1-cau" tabindex="-1">Tóm tắt 1 câu <a class="header-anchor" href="#tom-tat-1-cau" aria-label="Permalink to &quot;Tóm tắt 1 câu&quot;">​</a></h2><p><strong>Khách lẻ book SERIES TOUR (qua web, ghép đoàn 15-20). Khách nhóm ≥10 người dùng INQUIRY FORM (Vivu liên hệ quote manual). Vivu nội bộ allocate HOTEL theo allotment đã contract trước. Khách KHÔNG bao giờ trực tiếp book hotel (ADR-001).</strong></p><hr><h2 id="_2-loai-tour-vivu-phuc-vu" tabindex="-1">2 loại tour Vivu phục vụ <a class="header-anchor" href="#_2-loai-tour-vivu-phuc-vu" aria-label="Permalink to &quot;2 loại tour Vivu phục vụ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Đặc điểm</th><th>Series Tour (Tour ghép)</th><th>Private Tour / Corporate</th></tr></thead><tbody><tr><td>Nguồn khách</td><td>Khách lẻ 1-4 người</td><td>Nhóm ≥10 (công ty, đại gia đình)</td></tr><tr><td>Ngày khởi hành</td><td>Vivu set trước (15/06, 22/06...)</td><td>Khách yêu cầu ngày tự do</td></tr><tr><td>Đoàn</td><td>Ghép 15-20 khách lạ</td><td>1 nhóm riêng</td></tr><tr><td>Giá</td><td>Niêm yết per-pax</td><td>Quote riêng theo nhóm</td></tr><tr><td>Booking flow</td><td><strong>Online</strong> — book trực tiếp</td><td><strong>Inquiry form</strong> → admin liên hệ quote</td></tr><tr><td>Entity DB chính</td><td><code>TourDeparture</code> → <code>Booking</code> → <code>TourBooking</code></td><td><code>InquiryRequest</code> → (chốt deal) → admin tạo <code>Booking</code> tay</td></tr><tr><td>Phase 1 ratio</td><td>~70% revenue</td><td>~30% revenue (biên cao hơn)</td></tr></tbody></table><p><strong>Vì sao tách 2 flow</strong> (ADR-006):</p><ul><li>Private Tour không thể book online vì cần custom (hotel theo yêu cầu, route theo yêu cầu, payment terms B2B, VAT đỏ).</li><li>Series Tour không thể quote tay vì cần xử lý nhanh + thanh toán online + ghép đoàn tự động.</li><li>Trộn 2 flow → schema phức tạp, UX khó hiểu. Tách sạch → đơn giản.</li></ul><hr><h2 id="flow-series-tour-—-4-buoc" tabindex="-1">Flow Series Tour — 4 bước <a class="header-anchor" href="#flow-series-tour-—-4-buoc" aria-label="Permalink to &quot;Flow Series Tour — 4 bước&quot;">​</a></h2><h3 id="buoc-1-—-vivu-chuan-bi-truoc-khi-mo-ban" tabindex="-1">Bước 1 — Vivu chuẩn bị (trước khi mở bán) <a class="header-anchor" href="#buoc-1-—-vivu-chuan-bi-truoc-khi-mo-ban" aria-label="Permalink to &quot;Bước 1 — Vivu chuẩn bị (trước khi mở bán)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Founder/Ops ký contract Hotel ABC: &quot;giữ 100 phòng-đêm/tháng 6&quot;</span></span>
<span class="line"><span>2. Admin nhập HotelAllotment:</span></span>
<span class="line"><span>     hotelId=ABC, periodMonth=2026-06-01, contractedRooms=100</span></span>
<span class="line"><span>3. Admin tạo Tour Đà Lạt 4N3Đ:</span></span>
<span class="line"><span>     - priceAdult=4.5tr, priceChild=3.3tr, priceInfant=0</span></span>
<span class="line"><span>     - TourOption: Deluxe upgrade +500k/pax, Single supplement +1.2tr</span></span>
<span class="line"><span>     - TourItinerary 3 đêm: hotelId=ABC, roomTypeNote=&quot;Twin Deluxe&quot;</span></span>
<span class="line"><span>4. Admin tạo TourDeparture 15/06: max=20, min=10, cancellationDeadline=08/06</span></span>
<span class="line"><span>5. Publish tour: Tour.isActive=true, Departure.status=AVAILABLE</span></span></code></pre></div><h3 id="buoc-2-—-khach-book-online-real-time" tabindex="-1">Bước 2 — Khách book (online, real-time) <a class="header-anchor" href="#buoc-2-—-khach-book-online-real-time" aria-label="Permalink to &quot;Bước 2 — Khách book (online, real-time)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Anh Khoa chọn tour Đà Lạt 4N3Đ, chọn departure 15/06</span></span>
<span class="line"><span>2. Điền: 2 adult + 1 child + chọn &quot;Deluxe upgrade&quot;</span></span>
<span class="line"><span>3. Click &quot;Thanh toán&quot; → Server Action \`BookingService.createTourBooking()\`:</span></span>
<span class="line"><span>     a. require(user.isLoggedIn)        ← ADR-004 must-login</span></span>
<span class="line"><span>     b. transaction Serializable:</span></span>
<span class="line"><span>        - SELECT TourDeparture FOR UPDATE   ← pessimistic lock</span></span>
<span class="line"><span>        - Check slot: bookedCount + 3 &lt;= maxParticipants</span></span>
<span class="line"><span>        - Compute priceBreakdown:</span></span>
<span class="line"><span>            2 × 4.5tr (adult)             = 9.0tr</span></span>
<span class="line"><span>            1 × 3.3tr (child)             = 3.3tr</span></span>
<span class="line"><span>            3 × 500k (Deluxe per_pax)     = 1.5tr</span></span>
<span class="line"><span>            ──────────────────────────────────────</span></span>
<span class="line"><span>            Total                         = 13.8tr</span></span>
<span class="line"><span>        - INSERT Booking(status=PENDING, paymentDeadline=NOW+15min)</span></span>
<span class="line"><span>        - INSERT TourBooking(priceBreakdown=JSON, participants=3,</span></span>
<span class="line"><span>                              adultsCount=2, childrenCount=1, infantsCount=0)</span></span>
<span class="line"><span>        - UPDATE TourDeparture.bookedCount += 3</span></span>
<span class="line"><span>        - INSERT Payment(status=PENDING, method=VNPAY)</span></span>
<span class="line"><span>        - LOG ActivityLog</span></span>
<span class="line"><span>     c. Redirect tới VNPay với externalRef = Payment.id</span></span>
<span class="line"><span>4. VNPay → khách trả tiền → webhook về \`/api/payments/vnpay/webhook\`:</span></span>
<span class="line"><span>     - Verify signature</span></span>
<span class="line"><span>     - UPDATE Payment.status=SUCCESS, externalId=&lt;VNPay tx&gt;</span></span>
<span class="line"><span>     - UPDATE Booking.status=PAID</span></span>
<span class="line"><span>     - Send email confirm</span></span></code></pre></div><h3 id="buoc-3-—-vivu-allocate-phong-admin-ui-semi-manual" tabindex="-1">Bước 3 — Vivu allocate phòng (admin UI, semi-manual) <a class="header-anchor" href="#buoc-3-—-vivu-allocate-phong-admin-ui-semi-manual" aria-label="Permalink to &quot;Bước 3 — Vivu allocate phòng (admin UI, semi-manual)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Admin Dashboard L0 thấy Booking PAID mới</span></span>
<span class="line"><span>2. Admin tính: 3 người → 2 phòng Twin (2+1 share)</span></span>
<span class="line"><span>3. Admin vào HotelAllotment tháng 6:</span></span>
<span class="line"><span>     usedRooms += (2 phòng × 3 đêm) = 6</span></span>
<span class="line"><span>4. Admin email/call Hotel ABC: &quot;đặt 2 Twin Deluxe 15-18/06 cho khách Khoa, ref VV-001&quot;</span></span>
<span class="line"><span>5. Hotel ABC confirm → Admin update Booking.status=CONFIRMED</span></span>
<span class="line"><span>   (Phase 1.5+: hệ thống auto email Hotel khi booking PAID)</span></span></code></pre></div><h3 id="buoc-4-—-tour-dien-ra" tabindex="-1">Bước 4 — Tour diễn ra <a class="header-anchor" href="#buoc-4-—-tour-dien-ra" aria-label="Permalink to &quot;Bước 4 — Tour diễn ra&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 15/06: Anh Khoa lên xe Vivu → check-in Hotel ABC</span></span>
<span class="line"><span>2. 18/06: tour kết thúc → admin update Booking.status=COMPLETED</span></span>
<span class="line"><span>3. Admin update TourDeparture.actualCostPerPax (cho L1/L2 reporting)</span></span>
<span class="line"><span>4. Cuối tháng: Vivu invoice/pay Hotel ABC theo usedRooms</span></span>
<span class="line"><span>5. Email khách link review tour (chỉ enable khi COMPLETED)</span></span></code></pre></div><hr><h2 id="flow-private-tour-—-inquiry-request-3-buoc" tabindex="-1">Flow Private Tour — Inquiry Request 3 bước <a class="header-anchor" href="#flow-private-tour-—-inquiry-request-3-buoc" aria-label="Permalink to &quot;Flow Private Tour — Inquiry Request 3 bước&quot;">​</a></h2><h3 id="buoc-1-—-khach-submit-inquiry-online" tabindex="-1">Bước 1 — Khách submit inquiry (online) <a class="header-anchor" href="#buoc-1-—-khach-submit-inquiry-online" aria-label="Permalink to &quot;Bước 1 — Khách submit inquiry (online)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. HR công ty XYZ vào trang tour Đà Lạt 4N3Đ</span></span>
<span class="line"><span>2. Thấy CTA &quot;Đặt tour cho công ty / nhóm riêng (10+ người)&quot;</span></span>
<span class="line"><span>3. Click → form mở:</span></span>
<span class="line"><span>     - Tên + email + phone</span></span>
<span class="line"><span>     - Tên công ty: XYZ</span></span>
<span class="line"><span>     - Số người: 40</span></span>
<span class="line"><span>     - Ngày dự kiến: &quot;tuần 2 tháng 6, linh hoạt&quot;</span></span>
<span class="line"><span>     - Ngân sách: 200tr (optional)</span></span>
<span class="line"><span>     - Yêu cầu chi tiết: &quot;Hotel 4★+, có gala dinner&quot;</span></span>
<span class="line"><span>4. Submit → InquiryRequest tạo:</span></span>
<span class="line"><span>     - status=NEW</span></span>
<span class="line"><span>     - tourId=&lt;tour ban đầu&gt;</span></span>
<span class="line"><span>     - type=CORPORATE_GROUP</span></span>
<span class="line"><span>5. Auto-email reply &quot;Cảm ơn, Vivu sẽ liên hệ trong 24h&quot;</span></span></code></pre></div><h3 id="buoc-2-—-vivu-xu-ly-admin-manual" tabindex="-1">Bước 2 — Vivu xử lý (admin, manual) <a class="header-anchor" href="#buoc-2-—-vivu-xu-ly-admin-manual" aria-label="Permalink to &quot;Bước 2 — Vivu xử lý (admin, manual)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Dashboard L0 hiển thị inquiry mới → assign cho Ops Linh</span></span>
<span class="line"><span>   InquiryRequest.assignedTo=&lt;Linh.userId&gt;</span></span>
<span class="line"><span>2. Ops Linh gọi điện trong 24h → status=CONTACTED</span></span>
<span class="line"><span>3. Ops build quote custom (Excel): hotel + xe + guide + ăn uống</span></span>
<span class="line"><span>4. Email khách báo giá 5.2tr × 40 = 208tr → status=QUOTED</span></span></code></pre></div><h3 id="buoc-3-—-chot-deal-ngoai-he-thong-→-bridge-vao-he-thong" tabindex="-1">Bước 3 — Chốt deal (ngoài hệ thống → bridge vào hệ thống) <a class="header-anchor" href="#buoc-3-—-chot-deal-ngoai-he-thong-→-bridge-vao-he-thong" aria-label="Permalink to &quot;Bước 3 — Chốt deal (ngoài hệ thống → bridge vào hệ thống)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Khách OK quote → 2 bên ký HĐ giấy (B2B), chuyển khoản</span></span>
<span class="line"><span>2. Ops Linh tạo Booking thủ công:</span></span>
<span class="line"><span>     - Tạo TourDeparture riêng (max=40, custom date)</span></span>
<span class="line"><span>     - Tạo Booking + TourBooking với priceBreakdown tay</span></span>
<span class="line"><span>     - Link InquiryRequest.convertedBookingId = booking.id</span></span>
<span class="line"><span>     - UPDATE InquiryRequest.status=CONFIRMED</span></span>
<span class="line"><span>3. Sau đó flow giống Series Tour: confirm hotel allotment + tour run</span></span></code></pre></div><blockquote><p><strong>Note</strong>: Phase 1 Private Tour vẫn dùng <code>TourDeparture</code> model (admin tạo tay 1 departure riêng cho mỗi nhóm). Phase 2 cân nhắc tách model <code>PrivateBooking</code> nếu cần.</p></blockquote><hr><h2 id="status-transitions" tabindex="-1">Status transitions <a class="header-anchor" href="#status-transitions" aria-label="Permalink to &quot;Status transitions&quot;">​</a></h2><h3 id="booking" tabindex="-1">Booking <a class="header-anchor" href="#booking" aria-label="Permalink to &quot;Booking&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PENDING ──payment success──► PAID ──admin confirm──► CONFIRMED</span></span>
<span class="line"><span>   │                                                      │</span></span>
<span class="line"><span>   │ payment timeout (cron 15min)                         │ tour ngày cuối</span></span>
<span class="line"><span>   │ or admin cancel                                      ▼</span></span>
<span class="line"><span>   ▼                                                  COMPLETED</span></span>
<span class="line"><span>CANCELLED                                                 │</span></span>
<span class="line"><span>                                                          │ khách yêu cầu refund</span></span>
<span class="line"><span>                                                          ▼</span></span>
<span class="line"><span>                                                       REFUNDED</span></span></code></pre></div><table tabindex="0"><thead><tr><th>From</th><th>To</th><th>Trigger</th><th>Side effect</th></tr></thead><tbody><tr><td><code>PENDING</code></td><td><code>PAID</code></td><td>Payment webhook SUCCESS</td><td>Send email confirm, ActivityLog</td></tr><tr><td><code>PENDING</code></td><td><code>CANCELLED</code></td><td>Cron auto-cancel (paymentDeadline &lt; NOW)</td><td>Decrement <code>TourDeparture.bookedCount</code></td></tr><tr><td><code>PENDING</code></td><td><code>CANCELLED</code></td><td>Admin manual</td><td>Decrement bookedCount, email khách</td></tr><tr><td><code>PAID</code></td><td><code>CONFIRMED</code></td><td>Admin confirm sau khi hotel xác nhận</td><td>ActivityLog</td></tr><tr><td><code>CONFIRMED</code></td><td><code>COMPLETED</code></td><td>Admin set sau ngày tour kết thúc</td><td>Enable review link, email khách</td></tr><tr><td><code>COMPLETED</code></td><td><code>REFUNDED</code></td><td>Admin process refund</td><td>ActivityLog, không touch bookedCount</td></tr><tr><td><code>PAID</code>/<code>CONFIRMED</code></td><td><code>CANCELLED</code></td><td>Admin manual (force)</td><td>Decrement bookedCount, refund flow</td></tr></tbody></table><h3 id="tourdeparture" tabindex="-1">TourDeparture <a class="header-anchor" href="#tourdeparture" aria-label="Permalink to &quot;TourDeparture&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AVAILABLE ──bookedCount = max──► FULL</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    │ admin cancel (không đủ min)</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>CANCELLED</span></span></code></pre></div><h3 id="inquiryrequest" tabindex="-1">InquiryRequest <a class="header-anchor" href="#inquiryrequest" aria-label="Permalink to &quot;InquiryRequest&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NEW → CONTACTED → QUOTED → CONFIRMED (→ link Booking)</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    ├──► REJECTED</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    └──► EXPIRED (cron 30 ngày)</span></span></code></pre></div><hr><h2 id="edge-cases" tabindex="-1">Edge cases <a class="header-anchor" href="#edge-cases" aria-label="Permalink to &quot;Edge cases&quot;">​</a></h2><h3 id="ec-1-khach-bo-ngang-khi-đang-thanh-toan" tabindex="-1">EC-1: Khách bỏ ngang khi đang thanh toán <a class="header-anchor" href="#ec-1-khach-bo-ngang-khi-đang-thanh-toan" aria-label="Permalink to &quot;EC-1: Khách bỏ ngang khi đang thanh toán&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Khách click &quot;Thanh toán&quot; → Booking PENDING + bookedCount += 3</span></span>
<span class="line"><span>2. Khách đóng browser, không quay lại VNPay</span></span>
<span class="line"><span>3. 16 phút sau, cron job \`auto-cancel-pending-bookings\` (chạy 1 phút/lần):</span></span>
<span class="line"><span>     SELECT * FROM bookings WHERE status=&#39;PENDING&#39; AND payment_deadline &lt; NOW()</span></span>
<span class="line"><span>4. Mỗi booking → transaction:</span></span>
<span class="line"><span>     - UPDATE Booking.status = CANCELLED</span></span>
<span class="line"><span>     - UPDATE TourDeparture.bookedCount -= participants</span></span>
<span class="line"><span>     - LOG ActivityLog action=AUTO_CANCEL_TIMEOUT</span></span>
<span class="line"><span>5. Slot release → khách khác có thể book</span></span></code></pre></div><h3 id="ec-2-departure-khong-đu-min-participants" tabindex="-1">EC-2: Departure không đủ min participants <a class="header-anchor" href="#ec-2-departure-khong-đu-min-participants" aria-label="Permalink to &quot;EC-2: Departure không đủ min participants&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Tour 15/06: min=10, đến 08/06 (cancellationDeadline) chỉ booked 5</span></span>
<span class="line"><span>2. Admin nhận cảnh báo Dashboard L0</span></span>
<span class="line"><span>3. Admin quyết cancel:</span></span>
<span class="line"><span>     - UPDATE TourDeparture.status=CANCELLED</span></span>
<span class="line"><span>     - SET cancellationReason=&quot;Không đủ số lượng khách&quot;</span></span>
<span class="line"><span>4. Tất cả Booking của departure này → admin manual:</span></span>
<span class="line"><span>     - UPDATE Booking.status=CANCELLED (force)</span></span>
<span class="line"><span>     - Decrement bookedCount = 0</span></span>
<span class="line"><span>     - Trigger refund manual (qua VNPay dashboard)</span></span>
<span class="line"><span>5. Email khách: tour cancel, offer departure 22/06 cùng tour HOẶC refund</span></span>
<span class="line"><span>6. HotelAllotment.usedRooms giảm tương ứng (admin update tay)</span></span></code></pre></div><h3 id="ec-3-inquiry-het-han-auto-expire" tabindex="-1">EC-3: Inquiry hết hạn (auto-expire) <a class="header-anchor" href="#ec-3-inquiry-het-han-auto-expire" aria-label="Permalink to &quot;EC-3: Inquiry hết hạn (auto-expire)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. InquiryRequest status=NEW</span></span>
<span class="line"><span>2. 30 ngày sau, không update (no admin contact, no customer response)</span></span>
<span class="line"><span>3. Cron daily job:</span></span>
<span class="line"><span>     UPDATE inquiry_requests SET status=&#39;EXPIRED&#39;</span></span>
<span class="line"><span>     WHERE status IN (&#39;NEW&#39;, &#39;CONTACTED&#39;) AND updated_at &lt; NOW() - INTERVAL &#39;30 days&#39;</span></span>
<span class="line"><span>4. Admin có thể manually re-open nếu khách quay lại</span></span></code></pre></div><h3 id="ec-4-race-condition-—-2-khach-book-slot-cuoi" tabindex="-1">EC-4: Race condition — 2 khách book slot cuối <a class="header-anchor" href="#ec-4-race-condition-—-2-khach-book-slot-cuoi" aria-label="Permalink to &quot;EC-4: Race condition — 2 khách book slot cuối&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. TourDeparture max=20, bookedCount=18, có 2 slot</span></span>
<span class="line"><span>2. Khách A và B cùng lúc click &quot;Thanh toán&quot; cho 2 người</span></span>
<span class="line"><span>3. Server transaction A: SELECT FOR UPDATE → lock row → check 18+2≤20 OK</span></span>
<span class="line"><span>4. Server transaction B: SELECT FOR UPDATE → WAIT cho A commit</span></span>
<span class="line"><span>5. A commit: bookedCount=20</span></span>
<span class="line"><span>6. B unlock: check 20+2≤20 FAIL → throw DepartureFullError</span></span>
<span class="line"><span>7. B rollback → khách B nhận message &quot;Hết slot, chọn departure khác&quot;</span></span></code></pre></div><h3 id="ec-5-hotel-allotment-vuot-contract-admin-nhap-sai" tabindex="-1">EC-5: Hotel allotment vượt contract (admin nhập sai) <a class="header-anchor" href="#ec-5-hotel-allotment-vuot-contract-admin-nhap-sai" aria-label="Permalink to &quot;EC-5: Hotel allotment vượt contract (admin nhập sai)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Admin tạo HotelAllotment hotelId=ABC, periodMonth=2026-06-01,</span></span>
<span class="line"><span>   contractedRooms=100, usedRooms=95</span></span>
<span class="line"><span>2. Admin tăng usedRooms thêm 8 (tổng 103)</span></span>
<span class="line"><span>3. DB CHECK \`hotel_allotments_no_overuse\` reject:</span></span>
<span class="line"><span>     ERROR: new row for relation &quot;hotel_allotments&quot; violates check constraint</span></span>
<span class="line"><span>4. Service layer catch error → return business error &quot;Vượt allotment&quot;</span></span>
<span class="line"><span>5. Admin phải release rooms hoặc đàm phán thêm với hotel</span></span></code></pre></div><hr><h2 id="ranh-gioi-ai-lam-gi" tabindex="-1">Ranh giới ai làm gì <a class="header-anchor" href="#ranh-gioi-ai-lam-gi" aria-label="Permalink to &quot;Ranh giới ai làm gì&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Thực thể</th><th>Track ở đâu</th><th>Ai update</th><th>Phase 1 cách thức</th></tr></thead><tbody><tr><td>Tour package</td><td><code>tours</code>, <code>tour_itineraries</code>, <code>tour_options</code>, <code>tour_departures</code></td><td>Content admin</td><td>Form admin</td></tr><tr><td>Series Tour booking</td><td><code>bookings</code> + <code>tour_bookings</code> + <code>payments</code></td><td>Hệ thống tự động</td><td>Server Action + webhook</td></tr><tr><td>Private Tour inquiry</td><td><code>inquiry_requests</code></td><td>Khách submit + admin xử lý</td><td>Form web → admin manual workflow</td></tr><tr><td>Private Tour booking (sau chốt)</td><td><code>bookings</code> (admin tạo tay)</td><td>Ops admin</td><td>Tạo Booking + Departure riêng thủ công</td></tr><tr><td>Hotel info</td><td><code>hotels</code>, <code>rooms</code></td><td>Content admin</td><td>Form admin</td></tr><tr><td>Hotel allotment</td><td><code>hotel_allotments</code> (monthly)</td><td>Ops admin</td><td>Form admin nhập tay đầu tháng</td></tr><tr><td>Hotel reservation thực sự với hotel</td><td>(ngoài hệ thống)</td><td>Ops admin → call/email hotel</td><td>Phone/email — không track DB Phase 1</td></tr><tr><td>Refund khách</td><td>(ngoài hệ thống)</td><td>Ops admin → VNPay/MoMo dashboard</td><td>Manual qua portal payment gateway</td></tr></tbody></table><blockquote><p><strong>Lưu ý ADR-001 vĩnh viễn</strong>: Vivu không trở thành OTA hotel kể cả Phase 2. Mọi tương tác khách-Vivu đều qua <code>Booking + TourBooking</code>. Tương tác Vivu-hotel đi qua <code>HotelAllotment</code> + email/phone.</p></blockquote><hr><h2 id="lien-ket" tabindex="-1">Liên kết <a class="header-anchor" href="#lien-ket" aria-label="Permalink to &quot;Liên kết&quot;">​</a></h2><ul><li>Quy tắc nghiệp vụ (pricing, cancellation policy): <code>02-quy-tac-nghiep-vu.md</code></li><li>Thuật ngữ: <code>03-thuat-ngu.md</code></li><li>Ma trận tính năng: <code>04-ma-tran-tinh-nang.md</code></li><li>Spec DB: <code>../03-co-so-du-lieu/02-thiet-ke-bang.md</code></li><li>Concurrency lock chi tiết: <code>../03-co-so-du-lieu/03-toan-ven-concurrency.md</code></li><li>ADR liên quan: <code>../02-kien-truc/decisions/ADR-001</code>, <code>ADR-002</code>, <code>ADR-006</code></li></ul>`,57)])])}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
